messages.content:
Frida: تعديل التطبيق أثناء التشغيل.

الأساسيات:
frida -U -l script.js com.target.app

سكربت بسيط:
Java.perform(function() {
    var Main = Java.use('com.target.Main');
    Main.getToken.implementation = function() {
        console.log('Token requested!');
        return this.getToken();
    };
});

— يراقب: استدعاء getToken

تعديل القيمة:
    Main.isPremium.implementation = function() {
        return true;  // دائمًا مميز
    };

في 2024:
• Frida 16: يدعم iOS 18
• CVE-2024-31497: تجاوز Frida detection

الأدوات:
• objection: واجهة Frida
• r2frida: radare2 + Frida
• frida-trace: تتبع الدوال

الخطوات:

١. WSS إجباري:
wss://target.com/ws
# بدلاً من ws:// (نص عادي)

٢. Origin:
const origin = req.headers.origin;
if (!allowedOrigins.includes(origin)) {
    req.reject();
}

٣. مصادقة:
// أول رسالة: token
{
  "type": "auth",
  "token": "eyJ..."
}
// قبل: السماح بأي رسالة

٤. Rate limit:
let msgCount = {};
ws.on('message', () => {
    msgCount[ws.ip]++;
    if (msgCount[ws.ip] > 100) {
        ws.close();
    }
});

النتيجة: WebSocket آمن
